// CLX Video Outreach v1 — Resolve input
// Accepts:
//   * Schedule Trigger (batch mode — pulls preferred_channel=video leads)
//   * Manual Webhook { body: { lead_id } }
//   * Execute Workflow from Booking v2 48h fallback { lead_id }

const input = $input.item.json;
const leadId = (input.body && input.body.lead_id) || input.lead_id || null;

return {
  json: {
    lead_id: leadId,
    mode: leadId ? 'single' : 'batch'
  }
};

// CLX Video Outreach v1 — Normalize + preflight gates
// Gates (short-circuit via _skip):
//   1. lead row missing
//   2. preferred_channel is not 'video' (batch mode only — single mode bypasses)
//   3. client.video_enabled is not true
//   4. video_status already set (generating / ready / delivered)
//   5. channels_attempted already includes 'video'

const rows = $input.item.json;
const lead = Array.isArray(rows) ? rows[0] : rows;
const mode = $('Resolve Input').first().json.mode || 'batch';

if (!lead || !lead.id) {
  return { json: { _skip: true, skip_reason: 'lead_not_found' } };
}

const client = lead.clients || {};
const videoEnabled = client.video_enabled === true;
const monthlyCap = Number(client.video_monthly_cap) || 50;

// Batch mode must respect preferred_channel. Single mode (manual webhook
// or Booking 48h fallback) is an explicit ask — bypass the channel check
// but still respect video_enabled.
if (mode === 'batch' && String(lead.preferred_channel || '').toLowerCase() !== 'video') {
  return { json: { _skip: true, skip_reason: 'preferred_channel_mismatch', lead_id: lead.id, client_id: lead.client_id || null } };
}

if (!videoEnabled) {
  return { json: { _skip: true, skip_reason: 'client_video_not_enabled', lead_id: lead.id, client_id: lead.client_id || null } };
}

const existingStatus = String(lead.video_status || '').toLowerCase();
if (existingStatus === 'generating' || existingStatus === 'ready' || existingStatus === 'delivered') {
  return { json: { _skip: true, skip_reason: 'video_already_' + existingStatus, lead_id: lead.id, client_id: lead.client_id || null } };
}

const attempted = Array.isArray(lead.channels_attempted) ? lead.channels_attempted : [];
if (attempted.includes('video')) {
  return { json: { _skip: true, skip_reason: 'already_attempted_video', lead_id: lead.id, client_id: lead.client_id || null } };
}

return {
  json: {
    ...lead,
    _client: client,
    _monthly_cap: monthlyCap
  }
};

// CLX Video Outreach v1 — Monthly cap gate
// Tavus bills per render; video_monthly_cap is the client's per-calendar-
// month budget. We leave a small buffer (cap - 2) so in-flight callbacks
// don't blow the ceiling mid-month.

const lead = $('Normalize Lead').first().json;
if (lead._skip) return { json: lead };

const overlayRows = $('Fetch Niche Overlay').first().json;
const overlay = Array.isArray(overlayRows) ? overlayRows[0] : overlayRows;
const scriptTemplate = (overlay && overlay.video_script_template) || null;

const used = Number($input.item.json) || 0;
const cap = Number(lead._monthly_cap) || 50;
const buffer = Math.max(0, cap - 2);

if (used >= buffer) {
  return { json: { _skip: true, skip_reason: 'video_monthly_cap_exceeded', generations_this_month: used, cap, lead_id: lead.id, client_id: lead.client_id || null } };
}

if (!scriptTemplate) {
  return { json: { _skip: true, skip_reason: 'no_video_script_template_for_niche', niche: lead.niche || lead.product_type || null, lead_id: lead.id, client_id: lead.client_id || null } };
}

return { json: { ...lead, generations_this_month: used, cap, script_template: scriptTemplate } };

// CLX Video Outreach v1 — Interpolate script template
// Fills the niche's video_script_template with lead-specific tokens:
//   {first_name}, {company}, {city}, {industry}
// Downstream we send this to Claude Haiku for a light rewrite pass, then
// hand the final text to Tavus. This deterministic interpolation is the
// fallback in case the Claude step fails — Tavus still gets a usable
// script.

const lead = $input.item.json;

const firstName = (lead.full_name || '').split(' ')[0] || 'there';
const company = lead.company || 'your business';
const city = lead.city || 'your area';
const industry = lead.industry || (lead.product_type || '').replace(/_/g, ' ') || 'your industry';

const raw = String(lead.script_template || '')
  .replace(/\{first_name\}/g, firstName)
  .replace(/\{company\}/g, company)
  .replace(/\{city\}/g, city)
  .replace(/\{industry\}/g, industry);

return {
  json: {
    ...lead,
    interpolated_script: raw,
    first_name: firstName
  }
};

// CLX Video Outreach v1 — Parse Claude response + fallback
// Extracts the rewritten script from Claude's messages response. If the
// Claude call failed (no credential, rate limit, etc.), fall back to the
// deterministic interpolated_script so Tavus still gets valid input.

const resp = $input.item.json || {};
const lead = $('Interpolate Script').first().json;

let finalScript = null;
try {
  if (Array.isArray(resp.content) && resp.content[0] && resp.content[0].text) {
    finalScript = String(resp.content[0].text).trim();
  }
} catch (e) {
  finalScript = null;
}

// Fallback chain: Claude → interpolated → template
if (!finalScript) finalScript = lead.interpolated_script;
if (!finalScript) finalScript = lead.script_template;

// Tavus hard caps script length — keep at 1500 chars to be safe
finalScript = String(finalScript || '').slice(0, 1500);

return {
  json: {
    ...lead,
    final_script: finalScript,
    claude_ok: !!(resp && Array.isArray(resp.content) && resp.content.length)
  }
};

// CLX Video Outreach v1 — Parse Tavus response
// Tavus /v2/videos returns { video_id, status, hosted_url, ... } on
// success, or a 4xx error body on failure. continueOnFail means the raw
// error may land here — anything without a video_id is a failure.

const resp = $input.item.json || {};
const lead = $('Parse Claude Response').first().json;

const ok = !!(resp.video_id || resp.id);
const request_id = resp.video_id || resp.id || null;
const tavus_status = resp.status || null;
const error_message = ok ? null : (resp.message || resp.error || resp.detail || JSON.stringify(resp).slice(0, 500));

return {
  json: {
    ...lead,
    tavus_ok: ok,
    tavus_request_id: request_id,
    tavus_status,
    tavus_error: error_message
  }
};

// CLX Video Outreach v1 — Prep lead update
// Writes back video_request_id / video_script / video_status and appends
// 'video' to channels_attempted. On Tavus failure we leave lead_status
// untouched so the router can re-route on the next tick.

const parsed = $('Parse Tavus Response').first().json;
const lead = $('Parse Claude Response').first().json;

const attempted = Array.isArray(lead.channels_attempted) ? [...lead.channels_attempted] : [];
if (!attempted.includes('video')) attempted.push('video');

const fields = {
  channels_attempted: attempted,
  last_channel_attempted: 'video',
  last_channel_attempted_at: new Date().toISOString(),
  video_script: parsed.final_script,
  video_status: parsed.tavus_ok ? 'generating' : 'failed'
};

if (parsed.tavus_ok) {
  fields.video_request_id = parsed.tavus_request_id;
  fields.lead_status = 'Video Generating';
}

const body = { p_lead_id: lead.id, p_fields: fields };

return { json: { ...parsed, rpc_body: JSON.stringify(body) } };
